+        .assert()
+        .success()
+        .get_output()
+        .stdout
+        .clone();
+
+    let json: Value = serde_json::from_slice(&output).expect("valid JSON");
+    let added = json["diff"]["new_issues"]
+        .as_array()
+        .expect("new_issues array");
+    assert_eq!(
